prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sourceName ?targetName ?edgeName WHERE {
  ?edge a bbo:SequenceFlow .
  ?edge bbo:has_sourceRef ?source .
  ?edge bbo:has_targetRef ?target .
  ?edge tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_2258986a_c790_4708_ae4e_8dc02b7d122d> .
  OPTIONAL { ?source bbo:name ?sourceName . }
  OPTIONAL { ?target bbo:name ?targetName . }
  OPTIONAL { ?edge bbo:name ?edgeName . }
}
ORDER BY ?sourceName ?targetName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?elemType ?elemName ?gatewayDir WHERE {
  ?elem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_2258986a_c790_4708_ae4e_8dc02b7d122d> .
  ?elem a ?elemType .
  OPTIONAL { ?elem bbo:name ?elemName . }
  OPTIONAL { ?elem bboExt:gatewayDirection ?gatewayDir . }
  FILTER(?elemType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway, bboExt:StartEvent))
}
